function polymoji_get_unicode_lookup_table() {
  return LookupTable;
}
function polymoji_get_unicode_points(emoji) {
  return Array.from([...LookupTable.entries()].find(([, value]) => value === emoji)?.[0] ?? "\uFFFD").map((char) => char.codePointAt(0).toString(16).toLowerCase());
}

// src/polymoji_lib.ts
var IPolymojiFont = class {
  getGlyph(emojiId) {
    return "";
  }
  getFontName() {
    return "";
  }
};

// src/default_font.ts
var DefaultFont = class {
  getGlyph(emojiId) {
    let file = polymoji_get_unicode_points(emojiId).join("-");
    if (file == "fffd") {
      return "SKIP";
    }
    return `https://cdn.jsdelivr.net/gh/twitter/twemoji@14.0.2/assets/72x72/${file}.png`;
  }
  getFontName() {
    return "twemoji";
  }
};

